={{
(() => {
  // 1. Pobierz wiadomość użytkownika
  const webhookData = $('Google chat webhook').first();
  const msg = webhookData && webhookData.json.body && webhookData.json.body.message 
              ? webhookData.json.body.message.toLowerCase().trim() 
              : "";

  // 2. Wykryj język
  const isPolish = /[ąęśćżźłóń]/.test(msg) || ["tak", "nie", "hej", "czesc", "dobra", "jasne", "wyslij", "dawaj", "pomysl"].some(word => msg.includes(word));

  // 3. Słowa kluczowe sugerujące chęć zapisu
  const submissionKeywords = ["tak", "yes", "potwierdzam", "confirm", "wysyłaj", "send", "zapisz", "save", "ok", "dobra", "jasne", "sure", "do it"];
  const isSubmissionAttempt = submissionKeywords.some(keyword => msg.includes(keyword));

  // 4. Link do formularza (Plan B - jako ostateczność)
  const formLink = "https://forms.gle/Z7XcQeKBMdMn9bne6";

  // --- NOWA LOGIKA ---

  // SCENARIUSZ A: User chciał zapisać, ale Agent się zawiesił.
  // Zamiast błędu, prosimy o silniejszą komendę ("Wyślij").
  if (isSubmissionAttempt) {
      if (isPolish) {
         return `⚠️ Zrozumiałem Twoje potwierdzenie, ale coś zablokowało mi dostęp do bazy (niejednoznaczny sygnał). 🔌\n\nSpróbujmy to przepchnąć – napisz proszę krótko: **"Wyślij"** lub **"Zapisz"**.\n\n(Jeśli to nadal nie zadziała, wtedy użyj tego formularza: ${formLink})`;
      } else {
         return `⚠️ I understood your confirmation, but the connection to the database stalled (ambiguous signal). 🔌\n\nLet's try to force it – please type: **"Send"** or **"Save"**.\n\n(If that still doesn't work, use this backup form: ${formLink})`;
      }
  }

  // SCENARIUSZ B: Rozmowa o czymś innym + zawieszenie Agenta
  else {
      if (isPolish) {
         return "⚠️ Ups, coś mi przerwało proces myślowy (otrzymałem pustą odpowiedź). 🧠\nCzy mógłbyś proszę powtórzyć lub przeformułować ostatnią wiadomość?";
      } else {
         return "⚠️ Oops, I lost my train of thought (received an empty response). 🧠\nCould you please repeat or rephrase your last message?";
      }
  }
})()
}}
